using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;using verii_metivon_api.Core.Auth;using verii_metivon_api.Core.Persistence;using verii_metivon_api.Modules.Sales.Application.Services;using verii_metivon_api.Modules.Sales.Domain.Entities;
namespace verii_metivon_api.Modules.Sales.Api;[ApiController,Authorize,Route("api/sales-orders")]public sealed class SalesOrdersController(ISalesOrderService service,MetivonDbContext db):ControllerBase{
[HttpGet]public async Task<IActionResult>List([FromQuery]SalesOrderQuery q,CancellationToken ct){var r=await service.GetPagedAsync(q,ct);return StatusCode(r.StatusCode,r);}
[HttpGet("{id:long}")]public async Task<IActionResult>Get(long id,CancellationToken ct){var e=await db.SalesOrders.AsNoTracking().Include(x=>x.Lines).FirstOrDefaultAsync(x=>x.Id==id,ct);if(e is null)return NotFound(ApiResponse<object>.Error("Sales order not found.",404));return Ok(ApiResponse<object>.Ok(new{e.OrderNumber,NumberSeriesId=(long?)null,e.BranchId,e.CustomerId,CustomerGroupId=(long?)null,e.CurrencyId,e.PaymentTermId,e.WarehouseId,e.OrderDate,e.RequestedShipmentDate,e.CustomerReference,e.ExchangeRate,Lines=e.Lines.OrderBy(x=>x.LineNumber).Select(x=>new{x.ProductId,x.UnitId,x.StorageLocationId,x.InventoryStatusId,x.InventoryLotId,x.InventorySerialId,Quantity=x.OrderedQuantity,x.UnitPrice,x.TaxRate,x.Notes})}));}
[HttpPost]public async Task<IActionResult>Create(CreateSalesOrderRequest x,CancellationToken ct){var r=await service.CreateAsync(x,ct);return StatusCode(r.StatusCode,r);}
[HttpPut("{id:long}")]public async Task<IActionResult>Update(long id,CreateSalesOrderRequest r,CancellationToken ct){var e=await db.SalesOrders.Include(x=>x.Lines).FirstOrDefaultAsync(x=>x.Id==id,ct);if(e is null)return NotFound(ApiResponse<object>.Error("Sales order not found.",404));if(e.Status!=SalesOrderStatus.Draft)return Conflict(ApiResponse<object>.Error("Only draft sales orders can be edited.",409));if(r.Lines.Count==0)return BadRequest(ApiResponse<object>.Error("At least one line is required.",400));var oldPrices=e.Lines.GroupBy(x=>(x.ProductId,x.UnitId)).ToDictionary(x=>x.Key,x=>x.First().UnitPrice);e.OrderNumber=string.IsNullOrWhiteSpace(r.OrderNumber)?e.OrderNumber:r.OrderNumber.Trim().ToUpperInvariant();e.BranchId=r.BranchId;e.CustomerId=r.CustomerId;e.CurrencyId=r.CurrencyId;e.PaymentTermId=r.PaymentTermId;e.WarehouseId=r.WarehouseId;e.OrderDate=r.OrderDate;e.RequestedShipmentDate=r.RequestedShipmentDate;e.CustomerReference=r.CustomerReference?.Trim();e.ExchangeRate=r.ExchangeRate;db.SalesOrderLines.RemoveRange(e.Lines);e.Lines=[];e.Subtotal=e.DiscountTotal=e.TaxTotal=e.GrandTotal=0;var n=0;foreach(var l in r.Lines){var unitPrice=l.UnitPrice??oldPrices.GetValueOrDefault((l.ProductId,l.UnitId));if(l.Quantity<=0||unitPrice<0)return BadRequest(ApiResponse<object>.Error("Line quantity and price are invalid.",400));var gross=l.Quantity*unitPrice;var tax=gross*l.TaxRate/100m;e.Lines.Add(new(){LineNumber=++n,Status=SalesLineStatus.Open,ProductId=l.ProductId,UnitId=l.UnitId,StorageLocationId=l.StorageLocationId,InventoryStatusId=l.InventoryStatusId,InventoryLotId=l.InventoryLotId,InventorySerialId=l.InventorySerialId,OrderedQuantity=l.Quantity,UnitPrice=unitPrice,TaxRate=l.TaxRate,TaxAmount=tax,LineTotal=gross+tax,Notes=l.Notes?.Trim()});e.Subtotal+=gross;e.TaxTotal+=tax;e.GrandTotal+=gross+tax;}await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.Ok(new{e.Id}));}
[HttpPost("{id:long}/confirm")]public async Task<IActionResult>Confirm(long id,CancellationToken ct){var r=await service.ConfirmAsync(id,ct);return StatusCode(r.StatusCode,r);}[HttpDelete("{id:long}")]public async Task<IActionResult>Delete(long id,CancellationToken ct){var e=await db.SalesOrders.Include(x=>x.Lines).FirstOrDefaultAsync(x=>x.Id==id,ct);if(e is null)return NotFound(ApiResponse<object>.Error("Sales order not found.",404));if(e.Status!=SalesOrderStatus.Draft)return Conflict(ApiResponse<object>.Error("Only draft sales orders can be deleted.",409));db.SalesOrders.Remove(e);await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.Ok(new{e.Id}));}}
